solution: class Solution {
public:
    int countSubstrings(string s) {
        int n = s.size(), ans = 0;
        for (int c = 0; c < n; ++c) {
            for (int l = 0; l < 2; ++l) {
                int left = c, right = c + l;
                while (left >= 0 && right < n && s[left] == s[right]) {
                    ++ans;
                    --left;
                    ++right;
                }
            }
        }
        return ans;
    }
};
